// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title ShadowOTC V2
 * @notice Comprehensive OTC deal system on Ritual Chain
 * @dev Supports all deal categories: Social, NFT, Whitelist, Airdrop,
 *      Token Allocation, Pre-Market, Freelance, Escrow, Collateral, Conditional
 */
contract ShadowOTCV2 {

    // ─────────────────────────────────────────────────────────────
    // ENUMS
    // ─────────────────────────────────────────────────────────────

    enum DealCategory {
        SOCIAL_MEDIA,       // 0 - Likes, followers, views, engagement
        CONTENT_CREATION,   // 1 - Blog posts, videos, articles, threads
        FREELANCE,          // 2 - Dev work, design, copywriting
        NFT_TRANSFER,       // 3 - Direct NFT OTC sale
        NFT_WHITELIST,      // 4 - Whitelist / allowlist spot
        AIRDROP_ALLOCATION, // 5 - Airdrop claim transfer
        TOKEN_ALLOCATION,   // 6 - Seed/private/KOL round allocation
        PRE_MARKET,         // 7 - Pre-TGE token price deal
        MARKETING,          // 8 - Promotions, backlinks, listings
        BUG_BOUNTY,         // 9 - Bug reports and fix verification
        ESCROW,             // 10 - Generic two-party escrow
        CONDITIONAL         // 11 - Custom condition-based deal
    }

    enum DealStatus {
        OPEN,               // 0 - Created, awaiting seller
        ACCEPTED,           // 1 - Seller accepted, work in progress
        PENDING_DELIVERY,   // 2 - Seller claims done, awaiting verification
        VERIFYING,          // 3 - Verifier agent checking condition
        COMPLETED,          // 4 - Verified, funds released to seller
        FAILED,             // 5 - Condition not met, funds refunded
        DISPUTED,           // 6 - Dispute raised, awaiting resolution
        CANCELLED,          // 7 - Cancelled before acceptance
        EXPIRED             // 8 - Deadline passed, auto-refunded
    }

    enum VerificationMethod {
        HTTP_FETCH,         // 0 - Fetch a URL and check content
        ON_CHAIN_READ,      // 1 - Read blockchain state directly
        MANUAL,             // 2 - Manual verifier confirmation
        DUAL                // 3 - Both HTTP and on-chain check
    }

    enum CollateralRequirement {
        NONE,               // 0 - No collateral required
        PARTIAL,            // 1 - Partial collateral (e.g. 30% of deal)
        FULL,               // 2 - Full collateral equal to deal value
        DOUBLE              // 3 - 2x collateral for high-risk deals
    }

    // ─────────────────────────────────────────────────────────────
    // STRUCTS
    // ─────────────────────────────────────────────────────────────

    struct Deal {
        // Parties
        address buyer;
        address seller;
        address verifier;           // Assigned verifier agent

        // Deal metadata
        DealCategory category;
        DealStatus status;
        VerificationMethod verificationMethod;
        CollateralRequirement collateralRequirement;

        // Financials
        uint256 paymentAmount;      // Total payment locked by buyer
        uint256 collateralAmount;   // Collateral locked by seller
        uint256 commitmentFee;      // Upfront fee released to seller on acceptance
        uint256 remainingPayment;   // Payment held until delivery confirmed

        // Timing
        uint256 createdAt;
        uint256 acceptedAt;
        uint256 deadline;           // Unix timestamp for delivery deadline
        uint256 deliveryClaimedAt;

        // Verification
        string intent;              // Human-readable deal description
        string conditionUrl;        // URL to verify condition
        string conditionParams;     // JSON params for verification (encrypted in TEE)
        string deliveryProof;       // Seller submits proof URL when done

        // Flags
        bool requiresCollateral;
        bool partialPaymentEnabled;
        bool autoRefundOnExpiry;
        bool disputed;
    }

    struct DealTemplate {
        DealCategory category;
        string name;
        string description;
        uint256 minBudget;
        uint256 defaultDeadlineHours;
        CollateralRequirement defaultCollateral;
        VerificationMethod verificationMethod;
        bool active;
    }

    struct DisputeRecord {
        uint256 dealId;
        address raisedBy;
        string reason;
        uint256 raisedAt;
        bool resolved;
        bool buyerWon;
    }

    // ─────────────────────────────────────────────────────────────
    // STATE
    // ─────────────────────────────────────────────────────────────

    uint256 public dealCounter;
    uint256 public templateCounter;
    address public owner;
    address public platformWallet;
    uint256 public platformFeePercent; // e.g. 100 = 1%

    mapping(uint256 => Deal) public deals;
    mapping(uint256 => DealTemplate) public templates;
    mapping(uint256 => DisputeRecord) public disputes;
    mapping(address => bool) public authorizedVerifiers;
    mapping(address => uint256[]) public buyerDeals;
    mapping(address => uint256[]) public sellerDeals;

    uint256 public constant MAX_DEADLINE_DAYS = 90;
    uint256 public constant MIN_COMMIT_FEE_PERCENT = 10; // 10% min commit fee
    uint256 public constant MAX_COMMIT_FEE_PERCENT = 50; // 50% max commit fee

    // ─────────────────────────────────────────────────────────────
    // EVENTS
    // ─────────────────────────────────────────────────────────────

    event DealCreated(
        uint256 indexed dealId,
        address indexed buyer,
        DealCategory category,
        uint256 amount,
        uint256 deadline
    );
    event DealAccepted(uint256 indexed dealId, address indexed seller, uint256 collateral);
    event DeliverySubmitted(uint256 indexed dealId, address indexed seller, string proofUrl);
    event DealCompleted(uint256 indexed dealId, uint256 sellerPayout, uint256 platformFee);
    event DealFailed(uint256 indexed dealId, string reason);
    event DealExpired(uint256 indexed dealId);
    event DealCancelled(uint256 indexed dealId);
    event DisputeRaised(uint256 indexed dealId, address indexed by, string reason);
    event DisputeResolved(uint256 indexed dealId, bool buyerWon);
    event CollateralDeposited(uint256 indexed dealId, address indexed seller, uint256 amount);
    event CommitFeeReleased(uint256 indexed dealId, address indexed seller, uint256 amount);
    event VerifierAssigned(uint256 indexed dealId, address indexed verifier);
    event TemplateAdded(uint256 indexed templateId, string name, DealCategory category);

    // ─────────────────────────────────────────────────────────────
    // MODIFIERS
    // ─────────────────────────────────────────────────────────────

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    modifier onlyVerifier(uint256 dealId) {
        require(
            msg.sender == deals[dealId].verifier || authorizedVerifiers[msg.sender],
            "Not authorized verifier"
        );
        _;
    }

    modifier dealExists(uint256 dealId) {
        require(dealId < dealCounter, "Deal does not exist");
        _;
    }

    // ─────────────────────────────────────────────────────────────
    // CONSTRUCTOR
    // ─────────────────────────────────────────────────────────────

    constructor(address _platformWallet, uint256 _feePercent) {
        owner = msg.sender;
        platformWallet = _platformWallet;
        platformFeePercent = _feePercent; // 100 = 1%
        _initializeTemplates();
    }

    // ─────────────────────────────────────────────────────────────
    // CORE FUNCTIONS
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Create a new deal. Buyer locks payment.
     * @param category Deal category (0-11)
     * @param intent Human-readable description
     * @param conditionUrl URL to verify against
     * @param conditionParams Verification parameters (TEE encrypted)
     * @param deadlineHours Hours until deal expires
     * @param commitFeePercent % of payment released to seller on acceptance (0 = none)
     * @param collateral Collateral requirement level
     * @param verificationMethod How to verify the deal
     */
    function createDeal(
        DealCategory category,
        string calldata intent,
        string calldata conditionUrl,
        string calldata conditionParams,
        uint256 deadlineHours,
        uint256 commitFeePercent,
        CollateralRequirement collateral,
        VerificationMethod verificationMethod
    ) external payable returns (uint256) {
        require(msg.value > 0, "Must lock payment");
        require(deadlineHours > 0 && deadlineHours <= MAX_DEADLINE_DAYS * 24, "Invalid deadline");
        require(commitFeePercent <= MAX_COMMIT_FEE_PERCENT, "Commit fee too high");

        uint256 dealId = dealCounter++;
        uint256 commitFee = (msg.value * commitFeePercent) / 100;
        uint256 remaining = msg.value - commitFee;

        deals[dealId] = Deal({
            buyer:                  msg.sender,
            seller:                 address(0),
            verifier:               address(0),
            category:               category,
            status:                 DealStatus.OPEN,
            verificationMethod:     verificationMethod,
            collateralRequirement:  collateral,
            paymentAmount:          msg.value,
            collateralAmount:       0,
            commitmentFee:          commitFee,
            remainingPayment:       remaining,
            createdAt:              block.timestamp,
            acceptedAt:             0,
            deadline:               block.timestamp + (deadlineHours * 1 hours),
            deliveryClaimedAt:      0,
            intent:                 intent,
            conditionUrl:           conditionUrl,
            conditionParams:        conditionParams,
            deliveryProof:          "",
            requiresCollateral:     collateral != CollateralRequirement.NONE,
            partialPaymentEnabled:  commitFeePercent > 0,
            autoRefundOnExpiry:     true,
            disputed:               false
        });

        buyerDeals[msg.sender].push(dealId);

        emit DealCreated(dealId, msg.sender, category, msg.value, deals[dealId].deadline);
        return dealId;
    }

    /**
     * @notice Seller accepts a deal. May need to deposit collateral.
     * @param dealId The deal to accept
     */
    function acceptDeal(uint256 dealId) external payable dealExists(dealId) {
        Deal storage deal = deals[dealId];
        require(deal.status == DealStatus.OPEN, "Deal not open");
        require(deal.buyer != msg.sender, "Buyer cannot be seller");
        require(block.timestamp < deal.deadline, "Deal expired");

        // Calculate required collateral
        uint256 requiredCollateral = _calcCollateral(deal);
        require(msg.value >= requiredCollateral, "Insufficient collateral");

        deal.seller = msg.sender;
        deal.collateralAmount = msg.value;
        deal.acceptedAt = block.timestamp;
        deal.status = DealStatus.ACCEPTED;

        sellerDeals[msg.sender].push(dealId);

        // Release commitment fee to seller immediately if set
        if (deal.commitmentFee > 0) {
            payable(msg.sender).transfer(deal.commitmentFee);
            emit CommitFeeReleased(dealId, msg.sender, deal.commitmentFee);
        }

        emit DealAccepted(dealId, msg.sender, msg.value);
        emit CollateralDeposited(dealId, msg.sender, msg.value);
    }

    /**
     * @notice Seller submits proof of delivery.
     * @param dealId The deal
     * @param proofUrl URL proving the work is done
     */
    function submitDelivery(uint256 dealId, string calldata proofUrl) external dealExists(dealId) {
        Deal storage deal = deals[dealId];
        require(deal.seller == msg.sender, "Not seller");
        require(deal.status == DealStatus.ACCEPTED, "Deal not accepted");
        require(block.timestamp < deal.deadline, "Deadline passed");

        deal.deliveryProof = proofUrl;
        deal.deliveryClaimedAt = block.timestamp;
        deal.status = DealStatus.PENDING_DELIVERY;

        emit DeliverySubmitted(dealId, msg.sender, proofUrl);
    }

    /**
     * @notice Verifier agent executes the deal after checking condition.
     * @param dealId The deal
     * @param success Whether condition was met
     * @param reason Explanation of verification result
     */
    function executeDeal(
        uint256 dealId,
        bool success,
        string calldata reason
    ) external onlyVerifier(dealId) dealExists(dealId) {
        Deal storage deal = deals[dealId];
        require(
            deal.status == DealStatus.PENDING_DELIVERY ||
            deal.status == DealStatus.ACCEPTED ||
            deal.status == DealStatus.VERIFYING,
            "Invalid status for execution"
        );

        deal.status = DealStatus.VERIFYING;

        if (success) {
            _completeDeal(dealId);
        } else {
            _failDeal(dealId, reason);
        }
    }

    /**
     * @notice Buyer or seller raises a dispute.
     * @param dealId The deal
     * @param reason Dispute reason
     */
    function raiseDispute(uint256 dealId, string calldata reason) external dealExists(dealId) {
        Deal storage deal = deals[dealId];
        require(
            msg.sender == deal.buyer || msg.sender == deal.seller,
            "Not a deal party"
        );
        require(
            deal.status == DealStatus.ACCEPTED ||
            deal.status == DealStatus.PENDING_DELIVERY,
            "Cannot dispute at this stage"
        );
        require(!deal.disputed, "Already disputed");

        deal.disputed = true;
        deal.status = DealStatus.DISPUTED;

        disputes[dealId] = DisputeRecord({
            dealId:     dealId,
            raisedBy:   msg.sender,
            reason:     reason,
            raisedAt:   block.timestamp,
            resolved:   false,
            buyerWon:   false
        });

        emit DisputeRaised(dealId, msg.sender, reason);
    }

    /**
     * @notice Owner resolves a dispute.
     * @param dealId The deal
     * @param buyerWins True if buyer wins dispute
     */
    function resolveDispute(uint256 dealId, bool buyerWins) external onlyOwner dealExists(dealId) {
        Deal storage deal = deals[dealId];
        require(deal.status == DealStatus.DISPUTED, "Not disputed");

        disputes[dealId].resolved = true;
        disputes[dealId].buyerWon = buyerWins;

        if (buyerWins) {
            _failDeal(dealId, "Dispute resolved: buyer won");
        } else {
            _completeDeal(dealId);
        }

        emit DisputeResolved(dealId, buyerWins);
    }

    /**
     * @notice Anyone can trigger expiry check on a deal past deadline.
     * @param dealId The deal
     */
    function checkExpiry(uint256 dealId) external dealExists(dealId) {
        Deal storage deal = deals[dealId];
        require(block.timestamp > deal.deadline, "Not expired yet");
        require(
            deal.status == DealStatus.OPEN ||
            deal.status == DealStatus.ACCEPTED ||
            deal.status == DealStatus.PENDING_DELIVERY,
            "Already finalized"
        );

        if (deal.autoRefundOnExpiry) {
            deal.status = DealStatus.EXPIRED;

            // Refund buyer remaining payment
            payable(deal.buyer).transfer(deal.remainingPayment);

            // Return seller collateral if any
            if (deal.collateralAmount > 0) {
                payable(deal.seller).transfer(deal.collateralAmount);
            }

            emit DealExpired(dealId);
        }
    }

    /**
     * @notice Buyer cancels a deal before seller accepts.
     * @param dealId The deal
     */
    function cancelDeal(uint256 dealId) external dealExists(dealId) {
        Deal storage deal = deals[dealId];
        require(deal.buyer == msg.sender, "Not buyer");
        require(deal.status == DealStatus.OPEN, "Can only cancel open deals");

        deal.status = DealStatus.CANCELLED;
        payable(deal.buyer).transfer(deal.paymentAmount);

        emit DealCancelled(dealId);
    }

    /**
     * @notice Assign a specific verifier to a deal.
     */
    function assignVerifier(uint256 dealId, address verifier) external dealExists(dealId) {
        Deal storage deal = deals[dealId];
        require(msg.sender == deal.buyer || msg.sender == owner, "Not authorized");
        require(authorizedVerifiers[verifier] || msg.sender == owner, "Verifier not authorized");

        deal.verifier = verifier;
        emit VerifierAssigned(dealId, verifier);
    }

    // ─────────────────────────────────────────────────────────────
    // VIEW FUNCTIONS
    // ─────────────────────────────────────────────────────────────

    function getDeal(uint256 dealId) external view returns (Deal memory) {
        return deals[dealId];
    }

    function getBuyerDeals(address buyer) external view returns (uint256[] memory) {
        return buyerDeals[buyer];
    }

    function getSellerDeals(address seller) external view returns (uint256[] memory) {
        return sellerDeals[seller];
    }

    function getTemplate(uint256 templateId) external view returns (DealTemplate memory) {
        return templates[templateId];
    }

    function getAllTemplates() external view returns (DealTemplate[] memory) {
        DealTemplate[] memory all = new DealTemplate[](templateCounter);
        for (uint256 i = 0; i < templateCounter; i++) {
            all[i] = templates[i];
        }
        return all;
    }

    function getDispute(uint256 dealId) external view returns (DisputeRecord memory) {
        return disputes[dealId];
    }

    function isExpired(uint256 dealId) external view returns (bool) {
        return block.timestamp > deals[dealId].deadline;
    }

    function getRequiredCollateral(uint256 dealId) external view returns (uint256) {
        return _calcCollateral(deals[dealId]);
    }

    // ─────────────────────────────────────────────────────────────
    // ADMIN FUNCTIONS
    // ─────────────────────────────────────────────────────────────

    function addAuthorizedVerifier(address verifier) external onlyOwner {
        authorizedVerifiers[verifier] = true;
    }

    function removeVerifier(address verifier) external onlyOwner {
        authorizedVerifiers[verifier] = false;
    }

    function updatePlatformFee(uint256 newFee) external onlyOwner {
        require(newFee <= 500, "Max 5% fee");
        platformFeePercent = newFee;
    }

    function updatePlatformWallet(address newWallet) external onlyOwner {
        platformWallet = newWallet;
    }

    function addTemplate(
        DealCategory category,
        string calldata name,
        string calldata description,
        uint256 minBudget,
        uint256 defaultDeadlineHours,
        CollateralRequirement defaultCollateral,
        VerificationMethod verificationMethod
    ) external onlyOwner {
        uint256 tid = templateCounter++;
        templates[tid] = DealTemplate({
            category:               category,
            name:                   name,
            description:            description,
            minBudget:              minBudget,
            defaultDeadlineHours:   defaultDeadlineHours,
            defaultCollateral:      defaultCollateral,
            verificationMethod:     verificationMethod,
            active:                 true
        });
        emit TemplateAdded(tid, name, category);
    }

    // ─────────────────────────────────────────────────────────────
    // INTERNAL FUNCTIONS
    // ─────────────────────────────────────────────────────────────

    function _completeDeal(uint256 dealId) internal {
        Deal storage deal = deals[dealId];
        deal.status = DealStatus.COMPLETED;

        uint256 payout = deal.remainingPayment;
        uint256 platformFee = (payout * platformFeePercent) / 10000;
        uint256 sellerPayout = payout - platformFee;

        // Pay seller
        payable(deal.seller).transfer(sellerPayout);

        // Pay platform fee
        if (platformFee > 0 && platformWallet != address(0)) {
            payable(platformWallet).transfer(platformFee);
        }

        // Return seller collateral
        if (deal.collateralAmount > 0) {
            payable(deal.seller).transfer(deal.collateralAmount);
        }

        emit DealCompleted(dealId, sellerPayout, platformFee);
    }

    function _failDeal(uint256 dealId, string memory reason) internal {
        Deal storage deal = deals[dealId];
        deal.status = DealStatus.FAILED;

        // Refund remaining payment to buyer
        payable(deal.buyer).transfer(deal.remainingPayment);

        // If collateral required, send collateral to buyer as compensation
        if (deal.collateralAmount > 0) {
            payable(deal.buyer).transfer(deal.collateralAmount);
        }

        emit DealFailed(dealId, reason);
    }

    function _calcCollateral(Deal storage deal) internal view returns (uint256) {
        if (deal.collateralRequirement == CollateralRequirement.NONE) return 0;
        if (deal.collateralRequirement == CollateralRequirement.PARTIAL) {
            return (deal.paymentAmount * 30) / 100;
        }
        if (deal.collateralRequirement == CollateralRequirement.FULL) {
            return deal.paymentAmount;
        }
        if (deal.collateralRequirement == CollateralRequirement.DOUBLE) {
            return deal.paymentAmount * 2;
        }
        return 0;
    }

    function _initializeTemplates() internal {
        // Social Media
        templates[templateCounter++] = DealTemplate({
            category: DealCategory.SOCIAL_MEDIA,
            name: "Social Media Engagement",
            description: "Get likes, followers, views, or comments on a social media post",
            minBudget: 0.005 ether,
            defaultDeadlineHours: 72,
            defaultCollateral: CollateralRequirement.PARTIAL,
            verificationMethod: VerificationMethod.HTTP_FETCH,
            active: true
        });

        // Content Creation
        templates[templateCounter++] = DealTemplate({
            category: DealCategory.CONTENT_CREATION,
            name: "Content Creation",
            description: "Create and publish content such as articles, videos, or threads",
            minBudget: 0.01 ether,
            defaultDeadlineHours: 168,
            defaultCollateral: CollateralRequirement.PARTIAL,
            verificationMethod: VerificationMethod.HTTP_FETCH,
            active: true
        });

        // Freelance
        templates[templateCounter++] = DealTemplate({
            category: DealCategory.FREELANCE,
            name: "Freelance Service",
            description: "Development, design, writing, or any digital deliverable",
            minBudget: 0.01 ether,
            defaultDeadlineHours: 336,
            defaultCollateral: CollateralRequirement.FULL,
            verificationMethod: VerificationMethod.HTTP_FETCH,
            active: true
        });

        // NFT Transfer
        templates[templateCounter++] = DealTemplate({
            category: DealCategory.NFT_TRANSFER,
            name: "NFT OTC Sale",
            description: "Private OTC sale of an NFT outside of public marketplaces",
            minBudget: 0.05 ether,
            defaultDeadlineHours: 48,
            defaultCollateral: CollateralRequirement.FULL,
            verificationMethod: VerificationMethod.ON_CHAIN_READ,
            active: true
        });

        // NFT Whitelist
        templates[templateCounter++] = DealTemplate({
            category: DealCategory.NFT_WHITELIST,
            name: "NFT Whitelist Spot",
            description: "Transfer of NFT mint whitelist or allowlist spot to buyer",
            minBudget: 0.02 ether,
            defaultDeadlineHours: 720,
            defaultCollateral: CollateralRequirement.FULL,
            verificationMethod: VerificationMethod.DUAL,
            active: true
        });

        // Airdrop Allocation
        templates[templateCounter++] = DealTemplate({
            category: DealCategory.AIRDROP_ALLOCATION,
            name: "Airdrop Allocation",
            description: "Transfer of confirmed airdrop allocation to buyer wallet",
            minBudget: 0.01 ether,
            defaultDeadlineHours: 168,
            defaultCollateral: CollateralRequirement.FULL,
            verificationMethod: VerificationMethod.DUAL,
            active: true
        });

        // Token Allocation
        templates[templateCounter++] = DealTemplate({
            category: DealCategory.TOKEN_ALLOCATION,
            name: "Token Allocation OTC",
            description: "Private round or KOL allocation sold at negotiated price",
            minBudget: 0.1 ether,
            defaultDeadlineHours: 720,
            defaultCollateral: CollateralRequirement.DOUBLE,
            verificationMethod: VerificationMethod.ON_CHAIN_READ,
            active: true
        });

        // Pre-Market
        templates[templateCounter++] = DealTemplate({
            category: DealCategory.PRE_MARKET,
            name: "Pre-Market Token Deal",
            description: "Buy tokens at pre-TGE price with delivery on launch date",
            minBudget: 0.05 ether,
            defaultDeadlineHours: 2160,
            defaultCollateral: CollateralRequirement.DOUBLE,
            verificationMethod: VerificationMethod.ON_CHAIN_READ,
            active: true
        });

        // Marketing
        templates[templateCounter++] = DealTemplate({
            category: DealCategory.MARKETING,
            name: "Marketing and Promotion",
            description: "Backlinks, newsletter features, podcast mentions, listings",
            minBudget: 0.01 ether,
            defaultDeadlineHours: 168,
            defaultCollateral: CollateralRequirement.PARTIAL,
            verificationMethod: VerificationMethod.HTTP_FETCH,
            active: true
        });

        // Bug Bounty
        templates[templateCounter++] = DealTemplate({
            category: DealCategory.BUG_BOUNTY,
            name: "Bug Bounty",
            description: "Report and verify bugs or security vulnerabilities",
            minBudget: 0.02 ether,
            defaultDeadlineHours: 72,
            defaultCollateral: CollateralRequirement.NONE,
            verificationMethod: VerificationMethod.HTTP_FETCH,
            active: true
        });

        // Escrow
        templates[templateCounter++] = DealTemplate({
            category: DealCategory.ESCROW,
            name: "Generic Escrow",
            description: "Two-party escrow for any agreed exchange of value",
            minBudget: 0.01 ether,
            defaultDeadlineHours: 168,
            defaultCollateral: CollateralRequirement.NONE,
            verificationMethod: VerificationMethod.MANUAL,
            active: true
        });

        // Conditional
        templates[templateCounter++] = DealTemplate({
            category: DealCategory.CONDITIONAL,
            name: "Conditional Payment",
            description: "Pay only if a specific condition on the internet is true",
            minBudget: 0.005 ether,
            defaultDeadlineHours: 168,
            defaultCollateral: CollateralRequirement.NONE,
            verificationMethod: VerificationMethod.HTTP_FETCH,
            active: true
        });
    }

    receive() external payable {}
}

